import { useState } from 'react'
import Name from './components/Name.js'

const App = () => {
  const [persons, setPersons] = useState([
    { name: 'Arto Hellas', number: '040-123456', id: 1 },
    { name: 'Ada Lovelace', number: '39-44-5323523', id: 2 },
    { name: 'Dan Abramov', number: '12-43-234345', id: 3 },
    { name: 'Mary Poppendieck', number: '39-23-6423122', id: 4 }
  ])
  const [newName, setNewName] = useState('')
  const [newNumber, setNewNumber] = useState('')
  const [newStringFilter, setStringFilter] = useState('')
  const [showAll, setShowAll] = useState(false)

  const addName = (event) => {
    event.preventDefault()
    const nameObject = {name: newName, number: newNumber}
    if (persons.some(personsName => personsName.name  === newName)) {
      return alert(`${newName} is already added to phonebook`)
    }
    setPersons(persons.concat(nameObject))
    setNewName('')
  }

  const handleNameChange = (event) => {
    console.log(event.target.value)
    setNewName(event.target.value)
  }

  const handleNumberChange = (event) => {
    console.log(event.target.value)
    setNewNumber(event.target.value)
  }

  const handleFilterInput = (event) => {
    console.log(event.target.value)
    setStringFilter(event.target.value)
  }

  const peopleToShow = showAll
    ? persons
    : persons.filter(personName => personName.name.includes(newStringFilter))



  return (
    <div>
      <h2>Phonebook</h2>
      <div>
        filter shown with <input value = {newStringFilter}
                        onChange = {handleFilterInput}
                        />
      </div>
      <form onSubmit = {addName}>
      <h2>add a new</h2>
        <div>
          name: <input value = {newName}
               onChange = {handleNameChange}
        />
        </div>
        <div>number: <input value = {newNumber}
              onChange = {handleNumberChange} /></div>
        <div>
          <button type="submit">add</button>
        </div>
      </form>
      <h2>Numbers</h2>
      <ul>
        {peopleToShow.map(name => <Name key = {name.name} person = {name}/>)}
      </ul>
    </div>
  )
}

export default App
